76	[Sum of two restriction maps]
77	  \label{def:Scheme_HModule_prime_toBiprod}
78	  \lean{AlgebraicGeometry.Scheme.HModule'_toBiprod}
79	  \uses{def:Scheme_HModule_prime, def:Scheme_HModule_prime_cohomologyPresheaf}
80	  Let $S$ be a Mayer--Vietoris square, $\mathcal F$ a sheaf of $k$-modules, and $n \in \mathbb N$. Define the morphism
81	  \[
82	    \toBiprod \;:\; H^{\prime n}(X_4, \mathcal F) \longrightarrow H^{\prime n}(X_2, \mathcal F) \oplus H^{\prime n}(X_3, \mathcal F)
83	  \]
84	  to be the biproduct lift of the two restriction maps induced by $X_2 \to X_4$ and $X_3 \to X_4$.

