48	
49	\section{Structure sheaf as a sheaf of abelian groups}
50	
51	\begin{definition}\leanok
52	[Structure sheaf as a sheaf of abelian groups]
53	  \label{def:Scheme_toAbSheaf}
54	  \lean{AlgebraicGeometry.Scheme.toAbSheaf}
55	  \uses{thm:HasSheafCompose_forget}
56	  Let $C$ be a scheme. The structure sheaf of $C$, viewed as a sheaf of abelian groups on the topology of opens of the underlying topological space of $C$, is obtained by post-composing the commutative-ring-valued structure sheaf with the forgetful composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$ of Chapter~\ref{chap:Cohomology_SheafCompose}.
