530	\begin{theorem}\leanok
531	[Linear hom-equivalence from an adjunction]
532	  \label{def:Adjunction_homLinearEquiv}
533	  \lean{CategoryTheory.Adjunction.homLinearEquiv}
534	  \uses{lemma:Adjunction_left_adjoint_linear}
535	  Let $F \dashv G$ be an adjunction between $R$-linear preadditive categories with $G$ additive and $R$-linear. Then for all objects $X$ and $Y$, the additive equivalence of the adjunction upgrades to an $R$-linear equivalence between $\Hom(FX, Y)$ and $\Hom(X, GY)$.
